mapper.select:
SELECT n.id, n.title, n.content, n.author_id, n.visibility, n.view_required, n.view_count, n.created_at, n.updated_at, u.name AS author_name, CASE WHEN nv.id IS NOT NULL THEN true ELSE false END AS is_viewed FROM gw_notices n JOIN itsm_users u ON n.author_id = u.id LEFT JOIN gw_notice_views nv ON nv.notice_id = n.id AND nv.user_id = #{currentUserId}
AND (n.title LIKE CONCAT('%', #{search}, '%') OR n.content LIKE CONCAT('%', #{search}, '%'))
ORDER BY n.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT EXISTS(
    SELECT 1 FROM gw_notice_views
    WHERE notice_id = #{noticeId} AND user_id = #{userId}
)
